{
  "provision": {
    "id": "JSON:API v1.1 § Top Level",
    "title": "JSON:API Top Level Document Structure",
    "jurisdiction": "JSON:API Specification (v1.1)",
    "source_url": "https://jsonapi.org/format/"
  },
  "rules": [
    {
      "id": "R1",
      "description": "Every JSON:API request and response document containing data MUST have a JSON object at the root defining the top level structure",
      "modality": "obligatory",
      "conditions": [
        {
          "id": "C1.1",
          "description": "Document contains data",
          "formalisable": true
        }
      ],
      "exceptions": [],
      "definitions": []
    },
    {
      "id": "R2",
      "description": "Top-level JSON object MUST contain at least one of: data, errors, meta, or extension-defined member",
      "modality": "obligatory",
      "conditions": [
        {
          "id": "C2.1",
          "description": "Document is a valid JSON:API document with root JSON object",
          "formalisable": true
        }
      ],
      "exceptions": [],
      "definitions": []
    },
    {
      "id": "R3",
      "description": "Primary data (data member) MUST be either: single resource object, single resource identifier object, null (for single resources) OR array of resource objects, array of resource identifier objects, or empty array (for collections)",
      "modality": "obligatory",
      "conditions": [
        {
          "id": "C3.1",
          "description": "data member is present at top level",
          "formalisable": true
        },
        {
          "id": "C3.2",
          "description": "Request targets single resource vs collection",
          "formalisable": true
        }
      ],
      "exceptions": [],
      "definitions": [
        {
          "term": "resource object",
          "definition": "JSON object with type and id members identifying a unique resource",
          "has_open_texture": false,
          "core_meaning": "Object containing required type/id pair per spec",
          "penumbra": ""
        },
        {
          "term": "resource identifier object",
          "definition": "Object containing type and id members only",
          "has_open_texture": false,
          "core_meaning": "Minimal {type: string, id: string}",
          "penumbra": ""
        }
      ]
    },
    {
      "id": "R4",
      "description": "Values of id, type, and lid members MUST be strings",
      "modality": "obligatory",
      "conditions": [
        {
          "id": "C4.1",
          "description": "Member is present in resource object",
          "formalisable": true
        }
      ],
      "exceptions": [],
      "definitions": []
    },
    {
      "id": "R5",
      "description": "Within a given API, each resource object's type and id pair MUST identify a single, unique resource",
      "modality": "obligatory",
      "conditions": [
        {
          "id": "C5.1",
          "description": "Multiple resource objects exist in document",
          "formalisable": true
        }
      ],
      "exceptions": [],
      "definitions": [
        {
          "term": "API",
          "definition": "Set of URIs controlled by a server or multiple servers acting as one",
          "has_open_texture": true,
          "core_meaning": "Single server + controlled endpoints",
          "penumbra": "Multiple federated servers acting as unified API"
        }
      ]
    },
    {
      "id": "R6",
      "description": "Objects defined by specification or extensions MUST NOT contain additional members unless otherwise noted",
      "modality": "prohibited",
      "conditions": [
        {
          "id": "C6.1",
          "description": "Object follows standard specification objects or applied extensions",
          "formalisable": true
        }
      ],
      "exceptions": [
        {
          "id": "E6.1",
          "description": "Extensions MAY define new members within document structure",
          "priority": "extension specification supersedes core spec",
          "source": "JSON:API § Extensions"
        }
      ],
      "definitions": []
    },
    {
      "id": "R7",
      "description": "Client and server implementations MUST ignore non-compliant members",
      "modality": "obligatory",
      "conditions": [
        {
          "id": "C7.1",
          "description": "Non-compliant members detected in objects",
          "formalisable": true
        }
      ],
      "exceptions": [],
      "definitions": []
    },
    {
      "id": "R8",
      "description": "In compound documents, all included resources MUST be represented as array of resource objects in top-level included member",
      "modality": "obligatory",
      "conditions": [
        {
          "id": "C8.1",
          "description": "Server includes related resources (compound document)",
          "formalisable": true
        }
      ],
      "exceptions": [],
      "definitions": [
        {
          "term": "compound document",
          "definition": "Response including related resources along with primary resources",
          "has_open_texture": false,
          "core_meaning": "Primary data + included related resources with full linkage",
          "penumbra": ""
        }
      ]
    },
    {
      "id": "R9",
      "description": "Every included resource object MUST be identified via chain of relationships originating in primary data (full linkage requirement)",
      "modality": "obligatory",
      "conditions": [
        {
          "id": "C9.1",
          "description": "Compound document with included member",
          "formalisable": true
        }
      ],
      "exceptions": [
        {
          "id": "E9.1",
          "description": "Relationship fields excluded due to sparse fieldsets requested by client",
          "priority": "client request takes precedence",
          "source": "JSON:API § Compound Documents"
        }
      ],
      "definitions": []
    },
    {
      "id": "R10",
      "description": "Compound document MUST NOT include more than one resource object for each type and id pair",
      "modality": "prohibited",
      "conditions": [
        {
          "id": "C10.1",
          "description": "Compound document processing",
          "formalisable": true
        }
      ],
      "exceptions": [],
      "definitions": []
    }
  ],
  "defeat_relations": [
    {
      "defeater_rule": "E6.1",
      "defeated_rule": "R6",
      "reason": "lex specialis (extension specification)",
      "strict": true
    },
    {
      "defeater_rule": "E9.1",
      "defeated_rule": "R9",
      "reason": "client request precedence (sparse fieldsets)",
      "strict": true
    }
  ],
  "discretionary_checkpoints": [
    {
      "id": "D1",
      "authority": "Server implementation",
      "decision": "Whether to provide compound documents with included resources",
      "constraints": ["MUST follow full linkage requirement unless sparse fieldsets", "MUST NOT duplicate type/id pairs"],
      "gated_rule": "R8"
    }
  ],
  "open_texture_terms": [
    {
      "term": "API",
      "type": "vague",
      "core": "Single server controlling set of URIs",
      "penumbra": "Multiple federated servers acting as unified API",
      "authority": "API implementer",
      "case_law": []
    },
    {
      "term": "full linkage",
      "type": "vague",
      "core": "Direct relationship chain from primary data to included resource",
      "penumbra": "Multi-hop relationship chains through intermediate resources",
      "authority": "JSON:API implementer",
      "case_law": []
    }
  ],
  "key_references": [
    {
      "author": "JSON:API Authors",
      "title": "JSON:API — Latest Specification (v1.1)",
      "year": 2020,
      "relevance": "Authoritative specification source for all rules extracted",
      "url": "https://jsonapi.org/format/"
    }
  ]
}
